Bash(PGPASSWORD=postgres psql -U postgres -d eos_db << 'EOF'
-- Tarifs disponibles
SELECT 'tarifs_eos' as table_tarif, COUNT\(*\) as nb FROM tarifs_eos
UNION ALL SELECT 'tarifs_enqueteur', COUNT\(*\) FROM tarifs_enqueteur
UNION ALL SELECT 'tarifs_client', COUNT\(*\) FROM tarifs_client;

-- Détail tarifs EOS
SELECT code, description, montant, actif FROM tarifs_eos ORDER BY code;

-- Détail tarifs enquêteur
SELECT code, description, montant, actif, enqueteur_id, client_id FROM tarifs_enqueteur ORDER BY code;
EOF)

Bash(PGPASSWORD=postgres psql -U postgres -d eos_db << 'EOF'
-- Dates de validité des tarifs EOS
SELECT code, montant, date_debut, date_fin, actif FROM tarifs_eos ORDER BY code, date_debut;

-- Dates de validité tarifs enquêteur
SELECT code, montant, date_debut, date_fin, actif FROM tarifs_enqueteur WHERE enqueteur_id IS NULL ORDER BY code, date_debut;

-- Dates de validité tarifs client PARTNER
SELECT code_lettre, montant, date_debut, date_fin, actif FROM tarifs_client ORDER BY code_lettre, date_debut;

-- Champs dates disponibles sur les donnees
SELECT 
  MIN\(datedenvoie\) as min_datedenvoie, MAX\(datedenvoie\) as max_datedenvoie,
  MIN\(created_at\)  as min_created_at,  MAX\(created_at\)  as max_created_at
FROM donnees WHERE statut_validation='archive';
EOF)
